div.script:
document.addEventListener("DOMContentLoaded", function () {

    const field = document.getElementById("updateRemarkField");
    const btn = document.getElementById("updateBtn");

    if (!field || !btn) return;

    function toggle() {
        btn.disabled = field.value.trim() === "";
    }

    field.addEventListener("input", toggle);

});

form.script:
document.addEventListener("DOMContentLoaded", function () {

    const field = document.getElementById("updateRemarkField");
    const attachment = document.getElementById("attachmentInput");
    const status = document.querySelector('select[name="status"]');
    const btn = document.getElementById("updateBtn");

    if (!field || !attachment || !status || !btn) return;

    function toggle() {
        const hasRemark = field.value.trim() !== "";
        const hasAttachment = attachment.files.length > 0;
        const hasStatus = status.value.trim() !== "";

        // Enable button only when all 3 fields are filled
        btn.disabled = !(hasRemark && hasAttachment && hasStatus);
    }

    field.addEventListener("input", toggle);
    attachment.addEventListener("change", toggle);
    status.addEventListener("change", toggle);

    // Initial check on page load
    toggle();
});
